package com.naenae.teacher.mypage.controller;
import com.naenae.common.user.domain.User;import com.naenae.teacher.auth.security.CustomUserDetails;import com.naenae.teacher.mypage.model.*;import com.naenae.teacher.mypage.service.TeacherMyPageService;import org.springframework.core.io.*;import org.springframework.http.*;import org.springframework.security.core.Authentication;import org.springframework.stereotype.Controller;import org.springframework.ui.Model;import org.springframework.web.bind.annotation.*;import org.springframework.web.multipart.MultipartFile;import org.springframework.web.servlet.mvc.support.RedirectAttributes;
@Controller public class TeacherMyPageController {private final TeacherMyPageService service;public TeacherMyPageController(TeacherMyPageService service){this.service=service;}@GetMapping("/teacher/mypage")public String page(Authentication a,Model m){m.addAttribute("profile",service.get(id(a)));return"teacher/mypage";}@PostMapping("/teacher/mypage")public String update(@RequestParam String nickname,@RequestParam(required=false)MultipartFile profileImage,Authentication a,RedirectAttributes r){try{service.update(id(a),nickname,profileImage);r.addFlashAttribute("successMessage","프로필을 수정했습니다.");}catch(IllegalArgumentException e){r.addFlashAttribute("errorMessage",e.getMessage());}return"redirect:/teacher/mypage";}@GetMapping("/teacher/mypage/profile-image")public ResponseEntity<Resource> image(Authentication a){ProfileImage i=service.image(id(a));return ResponseEntity.ok().contentType(MediaType.parseMediaType(i.contentType())).cacheControl(CacheControl.noCache()).body(new FileSystemResource(i.path()));}private Long id(Authentication a){if(a!=null&&a.getPrincipal()instanceof CustomUserDetails d){User u=d.getUser();return u.getId();}throw new IllegalStateException("로그인 정보가 없습니다.");}}